+var deaconHeartbeatCmd = &cobra.Command{
+	Use:   "heartbeat [action]",
+	Short: "Update the Deacon heartbeat",
+	Long: `Update the Deacon heartbeat file.
+
+The heartbeat signals to the daemon that the Deacon is alive and working.
